import { useMemo } from 'react';

import { CategoricalLegendRenderer } from './CategoricalLegendRenderer.js';
import { SequentialLegendRenderer } from './SequentialLegendRenderer.js';
import { ThresholdLegendRenderer } from './ThresholdLegendRenderer.js';
import { useMapConfig } from '../../hooks/use-map-config.js';

const LEGEND_RENDERERS = {
  sequential: <SequentialLegendRenderer />,
  categorical: <CategoricalLegendRenderer />,
  threshold: <ThresholdLegendRenderer />,
};

export const MapLegendRenderer = () => {
  const type = useMapConfig().legend?.type ?? undefined;

  return useMemo(() => (type ? LEGEND_RENDERERS[type] : null), [type]);
};
